// @ts-nocheck
const METADATA = {
    website: "https://github.com/ct-yx/shapez-mods",
    author: "ct-yx & Codex",
    name: "Balancer Variants",
    version: "1.0.4",
    id: "balancer-variants-ctyx",
    description: "Adds 4-way, 5-way, 8-way, 10-way and 16-way balancers to the vanilla balancer variants.",
    minimumGameVersion: ">=1.5.0",
};

const VARIANTS = [4, 5, 8, 10, 16].map(ways => ({
    ways,
    id: "balancer_" + ways + "way",
    variant: "balancer_" + ways + "way",
    name: ways + "-way balancer",
    nameZh: ways + "-way 平衡器",
    displayName: ways + "x",
}));

const VARIANT_BY_ID = new Map(VARIANTS.map(config => [config.variant, config]));

function getWideBalancerThroughput(root, config) {
    // The vanilla two-way balancer is 4 items/s. Every lane therefore owns
    // 2 items/s, including belt-upgrade scaling. This is the actual processor
    // charge rate, not only the value shown by the building information panel.
    return root.hubGoals.getProcessorBaseSpeed(
        shapez.enumItemProcessorTypes.balancer
    ) * config.ways / 2;
}

// The vanilla variant strip asks MetaBuilding for a Sprite and then injects
// its HTML into the card. Returning this tiny sprite-like object keeps the
// actual building texture intact while leaving the strip text-only.
const EMPTY_VARIANT_PREVIEW = {
    getAsHTML() {
        return "";
    },
};

function makePlainVariantCardOneTile(card, label) {
    // Vanilla hides labels in the variant strip and lets iconWrap determine
    // every card's dimensions. Once the image is deliberately removed, set
    // both explicitly so 4x/5x/8x/10x/16x remain a single square tile rather
    // than collapsing to the card's 3px horizontal padding.
    if (card && card.style) {
        card.style.width = "calc(25px * var(--ui-scale))";
        card.style.minWidth = "calc(25px * var(--ui-scale))";
        card.style.height = "calc(25px * var(--ui-scale))";
        card.style.minHeight = "calc(25px * var(--ui-scale))";
        card.style.display = "inline-flex";
        card.style.alignItems = "center";
        card.style.justifyContent = "center";
        card.style.gap = "0";
    }
    if (label && label.style) {
        label.style.display = "flex";
        label.style.width = "100%";
        label.style.height = "100%";
        label.style.alignItems = "center";
        label.style.justifyContent = "center";
        label.style.fontSize = "calc(8px * var(--ui-scale))";
        label.style.lineHeight = "1";
        label.style.fontWeight = "700";
        label.style.whiteSpace = "nowrap";
    }
}

function registerProcessorType(config) {
    const processorType = config.id;
    shapez.enumItemProcessorTypes[processorType] = processorType;
    shapez.MOD_ITEM_PROCESSOR_SPEEDS[processorType] = root =>
        getWideBalancerThroughput(root, config);
    shapez.MOD_ITEM_PROCESSOR_HANDLERS[processorType] = function(payload) {
        const components = payload && payload.entity && payload.entity.components;
        const ejector = components && components.ItemEjector;
        const processor = components && components.ItemProcessor;
        const items = payload && payload.items;
        const outItems = payload && payload.outItems;
        const availableSlots = ejector && Array.isArray(ejector.slots)
            ? ejector.slots.length
            : 0;

        // A variant can briefly be rebuilt while the placement preview is
        // changing. Do not let an incomplete preview produce a modulo-by-zero
        // slot or throw from the processor system.
        if (!processor || !items || !outItems || availableSlots === 0) return false;

        for (let index = 0; index < config.ways; ++index) {
            const item = typeof items.get === "function" ? items.get(index) : null;
            if (!item) continue;
            outItems.push({
                item,
                preferredSlot: processor.nextOutputSlot++ % availableSlots,
                doNotTrack: true,
            });
        }
        return true;
    };
}

function makeSlots(count, direction) {
    const slots = [];
    for (let index = 0; index < count; ++index) {
        slots.push({
            pos: new shapez.Vector(index, 0),
            direction,
        });
    }
    return slots;
}

function getWideBalancerStatistics(root, config) {
    if (!root || !root.gameMode || root.gameMode.throughputDoesNotMatter()) return [];

    const totalRate = getWideBalancerThroughput(root, config);
    const speedLabel = shapez.T
        && shapez.T.ingame
        && shapez.T.ingame.buildingPlacement
        && shapez.T.ingame.buildingPlacement.infoTexts
        ? shapez.T.ingame.buildingPlacement.infoTexts.speed
        : "Speed";
    const formattedRate = typeof shapez.formatItemsPerSecond === "function"
        ? shapez.formatItemsPerSecond(totalRate)
        : totalRate + " items/s";
    return [[speedLabel, formattedRate]];
}

function updateWideBalancer(entity, config) {
    const components = entity && entity.components;
    if (!components) return false;

    const acceptor = components.ItemAcceptor;
    const processor = components.ItemProcessor;
    const ejector = components.ItemEjector;
    const underlays = components.BeltUnderlays;
    if (!acceptor || !processor || !ejector || !underlays) return false;

    // The preview entity may be switched several times in a single frame.
    // Clear transient processing state before changing the slot topology so
    // queued outputs from the previous width cannot target stale slots.
    if (typeof processor.clear === "function") processor.clear();

    acceptor.setSlots(
        makeSlots(config.ways, shapez.enumDirection.bottom)
    );
    processor.type = shapez.enumItemProcessorTypes[config.id];
    processor.inputsPerCharge = 1;
    processor.processingRequirement = null;
    ejector.setSlots(
        makeSlots(config.ways, shapez.enumDirection.top)
    );
    underlays.underlays = makeSlots(
        config.ways,
        shapez.enumDirection.top
    );
    return true;
}

function replaceVariantCardsWithLabels(placer) {
    const meta = placer && placer.currentMetaBuilding && placer.currentMetaBuilding.get();
    const element = placer && placer.variantsElement;
    if (!meta || !element || typeof element.querySelector !== "function"
        || typeof meta.getAvailableVariants !== "function") {
        return;
    }

    // HUDBuildingPlacer keeps an explanatory node before the actual cards:
    //   #ingame_HUD_PlacerVariants > .explanation + .variants > .variant
    // Indexing variantsElement.children therefore points at the wrong DOM
    // level, leaving the generated iconWrap (and its N-tile blank box) alive.
    const variantsContainer = element.querySelector(".variants");
    const cards = variantsContainer && variantsContainer.children;
    if (!cards) return;

    let variants;
    try {
        variants = meta.getAvailableVariants(placer.root) || [];
    } catch (error) {
        return;
    }

    for (let index = 0; index < variants.length; ++index) {
        const config = VARIANT_BY_ID.get(variants[index]);
        if (!config) continue;

        const card = cards[index];
        if (!card) continue;
        const label = typeof card.querySelector === "function"
            ? card.querySelector(".label")
            : null;
        const icon = typeof card.querySelector === "function"
            ? card.querySelector(".iconWrap")
            : null;
        if (label) label.textContent = config.displayName;
        if (icon && icon.parentNode && typeof icon.parentNode.removeChild === "function") {
            // Removing, rather than merely emptying, iconWrap also removes its
            // data-tile-w/data-tile-h layout reservation for 4/5/8/... lanes.
            icon.parentNode.removeChild(icon);
        }
        makePlainVariantCardOneTile(card, label);
        if (card.classList && card.classList.add) {
            card.classList.add("shapez-mod-plain-variant");
        }
    }
}

class Mod extends shapez.Mod {
    init() {
        for (const config of VARIANTS) registerProcessorType(config);

        const metaBalancer = shapez.MetaBalancerBuilding;
        if (!metaBalancer || !this.modInterface.addVariantToExistingBuilding) {
            throw new Error("Balancer Variants requires the vanilla balancer API");
        }

        for (const config of VARIANTS) {
            this.modInterface.addVariantToExistingBuilding(metaBalancer, config.variant, {
                rotationVariants: [0],
                dimensions: new shapez.Vector(config.ways, 1),
                regularSpriteBase64: RESOURCES["balancer-" + config.ways + ".png"],
                blueprintSpriteBase64: RESOURCES["balancer-" + config.ways + "-blueprint.png"],
                name: config.name,
                description: "A " + config.ways + "-lane balancer variant.",
                isUnlocked: () => true,
            });
            this.modInterface.registerBuildingTranslation(metaBalancer, config.variant, {
                language: "zh-CN",
                name: config.nameZh,
                description: config.ways + " 路输入/输出的平衡器变形体。",
            });
        }

        // addVariantToExistingBuilding registers the variant list and sprite,
        // while the vanilla class still needs its component layout changed for
        // each custom width. No toolbar entry is added: T cycles these variants
        // exactly where the vanilla balancer's variants are shown.
        this.modInterface.extendClass(metaBalancer, ({ $old }) => ({
            getAdditionalStatistics(root, variant) {
                const config = VARIANT_BY_ID.get(variant);
                if (config) return getWideBalancerStatistics(root, config);
                return $old.getAdditionalStatistics.call(this, root, variant);
            },
            getPreviewSprite(rotationVariant, variant) {
                if (VARIANT_BY_ID.has(variant)) return EMPTY_VARIANT_PREVIEW;
                return $old.getPreviewSprite.call(this, rotationVariant, variant);
            },
            updateVariants(entity, rotationVariant, variant) {
                const config = VARIANT_BY_ID.get(variant);
                if (config) {
                    updateWideBalancer(entity, config);
                    return;
                }
                return $old.updateVariants.call(this, entity, rotationVariant, variant);
            },
        }));

        // The vanilla placer renders every variant as a large image card.
        // Keep the image for the actual building, but make this selector a
        // compact text-only list: 4x, 5x, 8x, 10x and 16x.
        if (shapez.HUDBuildingPlacer) {
            this.modInterface.extendClass(shapez.HUDBuildingPlacer, ({ $old }) => ({
                rerenderVariants(...args) {
                    const result = $old.rerenderVariants.apply(this, args);
                    replaceVariantCardsWithLabels(this);
                    return result;
                },
            }));
        }
    }
}

const RESOURCES = {
    "balancer-4.png": "data:image/png;base64,",
    "balancer-4-blueprint.png": "data:image/png;base64,",
    "balancer-5.png": "data:image/png;base64,",
    "balancer-5-blueprint.png": "data:image/png;base64,",
    "balancer-8.png": "data:image/png;base64,",
    "balancer-8-blueprint.png": "data:image/png;base64,",
    "balancer-10.png": "data:image/png;base64,",
    "balancer-10-blueprint.png": "data:image/png;base64,",
    "balancer-16.png": "data:image/png;base64,",
    "balancer-16-blueprint.png": "data:image/png;base64,",
};
